238	// TestLand_MergeRequired verifies the merge path: the target has advanced
239	// since the worker started. Land() creates a merge commit whose parents are
240	// [currentTip, workerSHA], and critically the worker's own commit is NOT
241	// rewritten — its parent is still baseSHA so replay sees the original inputs.
242	func TestLand_MergeRequired(t *testing.T) {
243		r := newLandTestRepo(t)
244		ops := RealLandingGitOps{}
245	
246		// Worker branches off baseSHA.
247		workerSHA := r.commitOn(r.baseSHA, "feature.txt", "feature-content\n", "feat: worker")
248	
249		// Meanwhile, a sibling lands a commit on main directly.
250		siblingSHA := r.commitOn(r.baseSHA, "sibling.txt", "sibling-content\n", "feat: sibling")
251		r.runGit("update-ref", "refs/heads/main", siblingSHA)
252	
253		// Now land the worker's result. currentTip = siblingSHA != baseSHA → merge.
254		req := LandRequest{
255			WorktreeDir:  r.dir,
256			BaseRev:      r.baseSHA,
257			ResultRev:    workerSHA,
258			BeadID:       "ddx-land-merge",
259			AttemptID:    "20260414T000001-ccdd",
260			TargetBranch: "main",
261		}
262		land, err := Land(r.dir, req, ops)
263		if err != nil {
264			t.Fatalf("Land: %v", err)
265		}
266		if land.Status != "landed" {
267			t.Fatalf("expected status=landed, got %q (reason=%q)", land.Status, land.Reason)
268		}
269		if !land.Merged {
270			t.Errorf("expected Merged=true on sibling-advanced tip, got false")
271		}
272		if land.NewTip == workerSHA {
273			t.Errorf("expected NewTip to be the merge commit (different from worker %s), got same SHA", workerSHA)
274		}
275		if got := r.resolveRef("refs/heads/main"); got != land.NewTip {
276			t.Errorf("main tip = %s, want %s", got, land.NewTip)
277		}
278		// Exactly one merge commit was created.
279		if n := r.mergeCommitCount("refs/heads/main"); n != 1 {
280			t.Errorf("expected 1 merge commit on main after merge path, got %d", n)
281		}
282		// The merge commit's parents must be [siblingSHA, workerSHA] (in that order:
283		// `git merge --no-ff` from a worktree at currentTip produces [currentTip, incoming]).
284		parents := r.commitParents(land.NewTip)
285		if len(parents) != 2 {
286			t.Fatalf("merge commit should have 2 parents, got %v", parents)
287		}
288		if parents[0] != siblingSHA {
289			t.Errorf("merge commit parent[0] = %s, want currentTip %s", parents[0], siblingSHA)
290		}
291		if parents[1] != workerSHA {
292			t.Errorf("merge commit parent[1] = %s, want workerSHA %s", parents[1], workerSHA)
293		}
294		// Replay fidelity: the worker's commit is NOT rewritten — its parent is still baseSHA.
295		workerParents := r.commitParents(workerSHA)
296		if len(workerParents) != 1 || workerParents[0] != r.baseSHA {
297			t.Errorf("worker commit parent = %v, want [%s] (replay fidelity)", workerParents, r.baseSHA)
298		}
299		// main should have baseSHA + siblingSHA + workerSHA + merge commit = 4 commits.
300		if n := r.commitCount("refs/heads/main"); n != 4 {
301			t.Errorf("expected 4 commits on main (base+sibling+worker+merge), got %d", n)
302		}
303	}
